// Ses dosyasını kaydet
const fs = require('fs');
const path = require('path');

const audioDir = '/data/media/radio';
if (!fs.existsSync(audioDir)) {
  fs.mkdirSync(audioDir, { recursive: true });
}

const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const fileName = `radio_${timestamp}.mp3`;
const filePath = path.join(audioDir, fileName);

// Audio verisini kaydet
const audioData = $input.first().json.body || $input.first().binary?.data;
if (audioData) {
  if (typeof audioData === 'string') {
    fs.writeFileSync(filePath, Buffer.from(audioData, 'base64'));
  } else {
    fs.writeFileSync(filePath, audioData);
  }
}

return [{
  json: {
    audio_url: `/media/radio/${fileName}`,
    audio_path: filePath,
    file_name: fileName,
    duration_estimate: Math.ceil(($('AI Radyo Metni Üretici').first()?.json?.output || '').split(/\s+/).length / 2.5),
    transcript: $('AI Radyo Metni Üretici').first()?.json?.output || ''
  }
}];
